tasks.starter:
# 1. Enable automated syncPolicy
kubectl patch application guestbook -n argocd \
  --type=merge \
  -p '{
    "spec": {
      "syncPolicy": {
        "automated": {
          "selfHeal": ___,    # true: auto-recover changes that differ from Git
          "prune": ___         # true: auto-delete resources absent from Git
        }
      }
    }
  }'

# 2. Introduce drift: manually change replicas of guestbook-ui
kubectl scale deployment guestbook-ui -n guestbook --replicas=5

# 3. Watch for OutOfSync then automatic recovery
kubectl get deployment guestbook-ui -n guestbook -w

# 4. Review drift history detected by ArgoCD
argocd app history guestbook
